            $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("Ocp-Apim-Subscription-Key", bingApiKey);

        using var resp = await Http.SendAsync(request);
        resp.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await resp.Content.ReadAsStreamAsync());
        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("webPages", out var pages) &&
            pages.TryGetProperty("value", out var items))
        {
            foreach (var item in items.EnumerateArray())
            {
                var name    = item.GetProperty("name").GetString();
                var url     = item.GetProperty("url").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                results.Add($"• {name}\n  URL: {url}\n  {snippet}");
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found.";
    }

    private static async Task<string> SearchFallbackAsync(string query)
    {
