 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ---------------------------------------------------------------------------
 // Research Agent – a .NET 10 console app that uses an AI agent with tools
 // to research a topic and summarize findings.
 // ---------------------------------------------------------------------------

 // --- Configuration --------------------------------------------------------

 var openAiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY")  ?? "";
 var openAiModel = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";
 var bingApiKey  = Environment.GetEnvironmentVariable("BING_API_KEY")   ?? "";   // optional

 if (string.IsNullOrWhiteSpace(openAiKey))
 {
     Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
     return 1;
 }

 // --- Tool instances -------------------------------------------------------

 var notebook  = new Notebook();
 var webSearch = new WebSearchTool(bingApiKey);

 // --- Build the chat client with tool support ------------------------------

 IChatClient client = new OpenAIClient(openAiKey)
     .GetChatClient(openAiModel)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()   // automatic tool-call dispatch
     .Build();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(webSearch.SearchAsync),
     AIFunctionFactory.Create(notebook.AddNote),
     AIFunctionFactory.Create(notebook.GetNotes),
 };

 // --- Prompt the user for a topic ------------------------------------------

 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided.");
     return 1;
 }

 Console.WriteLine($"\n🔍 Researching \"{topic}\" …\n");

 // --- Run the agent loop ---------------------------------------------------

 var systemPrompt = $"""
     You are a research assistant. Your job is to research the following topic
     thoroughly and produce a well-structured summary.

     TOPIC: {topic}

     Instructions:
     1. Use the SearchWeb tool to find relevant information. Perform multiple
        searches with different queries to get broad coverage.
     2. After each search, read the results carefully and use the AddNote tool
        to save the key facts, statistics, and insights you find.
     3. When you have gathered enough information (at least 3 searches), use the
        GetNotes tool to review everything you've collected.
     4. Finally, produce a comprehensive summary of your research findings,
        organized with clear headings and bullet points.

     Always cite which search results informed each part of your summary.
     """;

 var messages = new List<ChatMessage>
 {
     new(ChatRole.System, systemPrompt),
     new(ChatRole.User,   $"Please research this topic: {topic}"),
 };

 var options = new ChatOptions { Tools = [.. tools] };

 var response = await client.GetResponseAsync(messages, options);

 Console.WriteLine("═══════════════════════════════════════════════════════════");
 Console.WriteLine("  RESEARCH SUMMARY");
 Console.WriteLine("═══════════════════════════════════════════════════════════");
 Console.WriteLine(response.Text);
 Console.WriteLine("═══════════════════════════════════════════════════════════");
 Console.WriteLine($"\n📝 Notes collected: {notebook.Count}");

 return 0;

 // ===========================================================================
 // Tools
 // ===========================================================================

 // --- Web Search Tool -------------------------------------------------------

 /// <summary>
 /// Searches the web using the Bing Web Search API when a key is available,
 /// otherwise falls back to a lightweight HTML scrape of a search engine.
 /// </summary>
 sealed class WebSearchTool(string bingApiKey)
 {
     private static readonly HttpClient Http = new();
     private int _searchCount;

     [Description("Searches the web for a given query and returns a list of result snippets. Use this to find information about any topic.")]
     public async Task<string> SearchAsync(
         [Description("The search query string")] string query)
     {
         Interlocked.Increment(ref _searchCount);
         Console.WriteLine($"  🌐 [{_searchCount}] Searching: \"{query}\"");

         try
         {
             if (!string.IsNullOrWhiteSpace(bingApiKey))
                 return await SearchBingAsync(query);

             return await SearchFallbackAsync(query);
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     private async Task<string> SearchBingAsync(string query)
     {
         using var request = new HttpRequestMessage(HttpMethod.Get,
             $"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count=5");
         request.Headers.Add("Ocp-Apim-Subscription-Key", bingApiKey);

         using var resp = await Http.SendAsync(request);
         resp.EnsureSuccessStatusCode();

         using var doc = await JsonDocument.ParseAsync(await resp.Content.ReadAsStreamAsync());
         var results = new List<string>();

         if (doc.RootElement.TryGetProperty("webPages", out var pages) &&
             pages.TryGetProperty("value", out var items))
         {
             foreach (var item in items.EnumerateArray())
             {
                 var name    = item.GetProperty("name").GetString();
                 var url     = item.GetProperty("url").GetString();
                 var snippet = item.GetProperty("snippet").GetString();
                 results.Add($"• {name}\n  URL: {url}\n  {snippet}");
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : "No results found.";
     }

     private static async Task<string> SearchFallbackAsync(string query)
     {
         // Use the DuckDuckGo instant-answer API (JSON, no key required).
         var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
         using var resp = await Http.GetAsync(url);
         resp.EnsureSuccessStatusCode();
         using var doc = await JsonDocument.ParseAsync(await resp.Content.ReadAsStreamAsync());

         var results = new List<string>();

         // Abstract (main answer)
         var abstractText = doc.RootElement.GetProperty("AbstractText").GetString();
         var abstractUrl  = doc.RootElement.GetProperty("AbstractURL").GetString();
         if (!string.IsNullOrWhiteSpace(abstractText))
             results.Add($"• Summary: {abstractText}\n  Source: {abstractUrl}");

         // Related topics
         if (doc.RootElement.TryGetProperty("RelatedTopics", out var related))
         {
             foreach (var rt in related.EnumerateArray().Take(5))
             {
                 if (rt.TryGetProperty("Text", out var text) &&
                     rt.TryGetProperty("FirstURL", out var rtUrl))
                 {
                     results.Add($"• {text.GetString()}\n  URL: {rtUrl.GetString()}");
                 }
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : $"No instant results. Try a more specific query about: {query}";
     }
 }

 // --- Notebook Tool ---------------------------------------------------------

 /// <summary>
