 sealed class Notebook
 {
     private readonly List<string> _notes = [];

     public int Count => _notes.Count;

     [Description("Saves a research note. Use this to record key facts, data points, or insights discovered during web searches.")]
     public string AddNote(
         [Description("The note text to save")] string note)
     {
         _notes.Add(note);
         Console.WriteLine($"  📝 Note #{_notes.Count} saved ({note.Length} chars)");
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieves all saved research notes so far. Use this to review what you have collected before writing the summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         return string.Join("\n\n", _notes.Select((n, i) => $"[Note {i + 1}] {n}"));
     }
 }

