                 var url     = item.GetProperty("url").GetString();
                 var snippet = item.GetProperty("snippet").GetString();
                 results.Add($"• {name}\n  URL: {url}\n  {snippet}");
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : "No results found.";
     }

     private static async Task<string> SearchFallbackAsync(string query)
     {
         // Use the DuckDuckGo instant-answer API (JSON, no key required).
         var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
         using var resp = await Http.GetAsync(url);
         resp.EnsureSuccessStatusCode();
         using var doc = await JsonDocument.ParseAsync(await resp.Content.ReadAsStreamAsync());

         var results = new List<string>();

         // Abstract (main answer)
         var abstractText = doc.RootElement.GetProperty("AbstractText").GetString();
         var abstractUrl  = doc.RootElement.GetProperty("AbstractURL").GetString();
         if (!string.IsNullOrWhiteSpace(abstractText))
             results.Add($"• Summary: {abstractText}\n  Source: {abstractUrl}");

         // Related topics
         if (doc.RootElement.TryGetProperty("RelatedTopics", out var related))
         {
             foreach (var rt in related.EnumerateArray().Take(5))
             {
                 if (rt.TryGetProperty("Text", out var text) &&
                     rt.TryGetProperty("FirstURL", out var rtUrl))
                 {
                     results.Add($"• {text.GetString()}\n  URL: {rtUrl.GetString()}");
                 }
             }
         }

         return results.Count > 0
             ? string.Join("\n\n", results)
             : $"No instant results. Try a more specific query about: {query}";
     }
 }

